import React from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { ArrowLeft } from 'lucide-react';
import '../styles/Katalog.css';

const Login = ({ setIsLoggedIn }) => {
  const navigate = useNavigate();

  const handleLoginSubmit = (e) => {
    e.preventDefault();
    // Simulasi masuk akun berhasil
    setIsLoggedIn(true);
    // Kembali ke keranjang setelah berhasil masuk
    navigate('/keranjang');
  };

  return (
    <div className="katalog-wrapper" style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh' }}>
      <div className="katalog-overlay"></div>
      <div style={{ position: 'relative', zIndex: 10, background: 'white', padding: '40px', borderRadius: '12px', width: '100%', maxWidth: '400px' }}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', position: 'relative', marginBottom: '25px' }}>
          <ArrowLeft size={24} style={{ position: 'absolute', left: 0, cursor: 'pointer' }} onClick={() => navigate(-1)} />
          <div style={{ background: '#fed7aa', color: '#c2410c', padding: '6px 12px', fontWeight: 'bold', borderRadius: '4px' }}>CampBread</div>
        </div>
        <div style={{ textAlign: 'center', marginBottom: '30px' }}>
          <h2>Masuk ke Akun</h2>
          <p style={{ fontSize: '13px', color: '#6b7280' }}>Silakan masuk untuk melanjutkan pesanan</p>
        </div>
        <form onSubmit={handleLoginSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
          <input type="text" placeholder="Email atau Nomor HP" style={{ width: '100%', padding: '12px', border: '1px solid #ddd', borderRadius: '6px' }} required />
          <input type="password" placeholder="Kata Sandi" style={{ width: '100%', padding: '12px', border: '1px solid #ddd', borderRadius: '6px' }} required />
          <button type="submit" className="btn-add" style={{ padding: '14px', marginTop: '10px' }}>Masuk Sekarang</button>
        </form>
        <div style={{ textAlign: 'center', marginTop: '25px', fontSize: '13px' }}>
          Belum punya akun? <Link to="#" style={{ color: '#3b82f6', fontWeight: '600' }}>Daftar</Link>
        </div>
      </div>
    </div>
  );
};

export default Login;
